public sealed class Warehouse : Entity<Guid> { public const int NameMaxLength = 200; public Warehouse(Guid id, Guid workspaceId, string name, DateTimeOffset createdAtUtc) : base(id) { if (id == Guid.Empty || workspaceId == Guid.Empty || createdAtUtc.Offset != TimeSpan.Zero) throw new DomainException("Warehouse values are invalid."); WorkspaceId = workspaceId; Name = NormalizeName(name); CreatedAtUtc = createdAtUtc; } public Guid WorkspaceId { get; private set; } public string Name { get; private set; } public DateTimeOffset CreatedAtUtc { get; private set; } public DateTimeOffset? ArchivedAtUtc { get; private set; } public static string NormalizeName(string name) { var value = name?.Trim() ?? string.Empty; if (string.IsNullOrWhiteSpace(value) || value.Length > NameMaxLength) throw new DomainException("Warehouse name is invalid."); return value; } public void Archive(DateTimeOffset value) { if (value.Offset != TimeSpan.Zero) throw new DomainException("Warehouse archive time must be UTC."); ArchivedAtUtc ??= value; } }

