using InventoryFlow.Domain.Entities;

namespace InventoryFlow.Application.Features.Suppliers;

/// <summary>Provides workspace-scoped persistence operations for suppliers.</summary>
public interface ISupplierCatalog
{
    /// <summary>Creates a supplier.</summary>
    Task<Supplier> CreateAsync(Supplier supplier, CancellationToken cancellationToken);
    /// <summary>Lists active suppliers.</summary>
    Task<IReadOnlyList<Supplier>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken);
    /// <summary>Finds a supplier only within its workspace.</summary>
    Task<Supplier?> FindAsync(Guid workspaceId, Guid supplierId, CancellationToken cancellationToken);
    /// <summary>Idempotently archives a supplier only within its workspace.</summary>
    Task<bool> ArchiveAsync(Guid workspaceId, Guid supplierId, DateTimeOffset archivedAtUtc, CancellationToken cancellationToken);
    /// <summary>Persists pending changes.</summary>
    Task SaveChangesAsync(CancellationToken cancellationToken);
}

/// <summary>Represents a duplicate normalized supplier name within a workspace.</summary>
public sealed class SupplierNameConflictException : Exception
{
    /// <summary>Initializes the exception.</summary>
    public SupplierNameConflictException() : base("A supplier with this name already exists in the workspace.") { }
}

using InventoryFlow.Application.Features.Suppliers;
using InventoryFlow.Domain.Entities;
using InventoryFlow.Infrastructure.Persistence;
using Microsoft.Data.SqlClient;
using Microsoft.EntityFrameworkCore;

namespace InventoryFlow.Infrastructure.Suppliers;

/// <summary>Persists workspace-scoped suppliers with SQL Server uniqueness and lifecycle handling.</summary>
public sealed class EfSupplierCatalog(ApplicationDbContext dbContext) : ISupplierCatalog
{
    /// <inheritdoc />
    public async Task<Supplier> CreateAsync(Supplier supplier, CancellationToken cancellationToken)
    {
        dbContext.Suppliers.Add(supplier);
        try
        {
            await dbContext.SaveChangesAsync(cancellationToken);
            return supplier;
        }
        catch (DbUpdateException exception) when (exception.InnerException is SqlException { Number: 2601 or 2627 })
        {
            throw new SupplierNameConflictException();
        }
    }

    /// <inheritdoc />
    public async Task<IReadOnlyList<Supplier>> ListActiveAsync(Guid workspaceId, CancellationToken cancellationToken) =>
        await dbContext.Suppliers.AsNoTracking().Where(supplier => supplier.WorkspaceId == workspaceId &&
            supplier.ArchivedAtUtc == null).OrderBy(supplier => supplier.Name).ThenBy(supplier => supplier.Id)
            .ToListAsync(cancellationToken);

    /// <inheritdoc />
    public Task<Supplier?> FindAsync(Guid workspaceId, Guid supplierId, CancellationToken cancellationToken) =>
        dbContext.Suppliers.SingleOrDefaultAsync(supplier => supplier.WorkspaceId == workspaceId && supplier.Id == supplierId,
            cancellationToken);

    /// <inheritdoc />
    public async Task<bool> ArchiveAsync(Guid workspaceId, Guid supplierId, DateTimeOffset archivedAtUtc,
        CancellationToken cancellationToken)
    {
        var supplier = await dbContext.Suppliers.SingleOrDefaultAsync(item => item.WorkspaceId == workspaceId &&
            item.Id == supplierId, cancellationToken);
        if (supplier is null) return false;
        supplier.Archive(archivedAtUtc);
        await dbContext.SaveChangesAsync(cancellationToken);
        return true;
    }

    /// <inheritdoc />
    public async Task SaveChangesAsync(CancellationToken cancellationToken) => await dbContext.SaveChangesAsync(cancellationToken);
}

using InventoryFlow.Domain.Entities;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

namespace InventoryFlow.Infrastructure.Persistence.Configurations;

/// <summary>Configures supplier persistence.</summary>
public sealed class SupplierConfiguration : IEntityTypeConfiguration<Supplier>
{
    /// <inheritdoc />
    public void Configure(EntityTypeBuilder<Supplier> builder)
    {
        builder.ToTable("Suppliers");
        builder.HasKey(supplier => supplier.Id);
        builder.Property(supplier => supplier.Name).HasMaxLength(Supplier.NameMaxLength).IsRequired();
        builder.Property(supplier => supplier.CreatedAtUtc).IsRequired();
        builder.HasIndex(supplier => new { supplier.WorkspaceId, supplier.Name }).IsUnique();
        builder.HasIndex(supplier => new { supplier.WorkspaceId, supplier.ArchivedAtUtc, supplier.Name, supplier.Id });
        builder.HasOne<Workspace>().WithMany().HasForeignKey(supplier => supplier.WorkspaceId).OnDelete(DeleteBehavior.Cascade);
    }
}

